import React, { useState, useEffect } from 'react';
import './Settings.css';
import ImportDataSidebar from './ImportDataSidebar'; // Ensure ImportDataSidebar is imported

function Settings() {
  const [domain, setDomain] = useState('');
  const [username, setJiraUsername] = useState('');
  const [apiToken, setJiraApiToken] = useState('');
  const [locked, setLocked] = useState(true);
  const [credentials, setCredentials] = useState([]);
  const [checkedCredentials, setCheckedCredentials] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [selectedCredential, setSelectedCredential] = useState(null); // Manage selected credentials here

  // Fetch stored credentials from the backend
  const fetchCredentials = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('https://localhost:7216/api/Auth/credentials');
      if (!response.ok) {
        throw new Error('Failed to fetch credentials');
      }
      const data = await response.json();
      setCredentials(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCredentials();
  }, []);

  const handleLockToggle = () => {
    setLocked(!locked);
  };

  const handleDelete = async (id) => {
    try {
      const response = await fetch(`https://localhost:7216/api/Auth/delete/${id}`, {
        method: 'DELETE',
      });
      if (response.ok) {
        setCredentials(credentials.filter((cred) => cred.id !== id));
      } else {
        throw new Error('Failed to delete credential');
      }
    } catch (err) {
      setError(err.message);
    }
  };

  const handleCheckboxChange = (id) => {
    if (checkedCredentials.includes(id)) {
      setCheckedCredentials(checkedCredentials.filter((checkboxId) => checkboxId !== id));
    } else {
      setCheckedCredentials([...checkedCredentials, id]);
    }
  };

  const handleSave = async () => {
    try {
      const payload = { domain, username, apiToken };
      const response = await fetch('https://localhost:7216/api/Auth/save', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      if (response.ok) {
        fetchCredentials(); // Refresh the credentials after saving
      } else {
        throw new Error('Failed to save credentials');
      }
    } catch (err) {
      setError(err.message);
    }
  };

  const handleLoad = () => {
    if (checkedCredentials.length === 1) {
      // Fetch the selected credential and set it as selectedCredential
      const selectedCredential = credentials.find((cred) => checkedCredentials.includes(cred.id));
      if (selectedCredential) {
        setSelectedCredential(selectedCredential); // Update state with selected credentials
      }
    }
  };

  return (
    <div className="settings-container">
      <h2>Jira Settings</h2>
      {error && <div className="error">{error}</div>}

      <div className="credentials-form">
        <div className="field">
          <label>Domain</label>
          <input
            type="text"
            value={domain}
            onChange={(e) => setDomain(e.target.value)}
            disabled={locked}
          />
        </div>

        <div className="field">
          <label>Jira Username</label>
          <input
            type="text"
            value={username}
            onChange={(e) => setJiraUsername(e.target.value)}
            disabled={locked}
          />
        </div>

        <div className="field">
          <label>Jira API Token</label>
          <input
            type="password"
            value={apiToken}
            onChange={(e) => setJiraApiToken(e.target.value)}
            disabled={locked}
          />
        </div>

        <div className="button-container">
          <button className="save-button" onClick={handleSave} disabled={locked}>Save</button>
          <div className="lock-checkbox">
            <input
              type="checkbox"
              checked={!locked}
              onChange={handleLockToggle}
            />
            <label>{locked ? 'Unlock Fields' : 'Lock Fields'}</label>
          </div>
          <button
            className="load-button"
            onClick={handleLoad}
            disabled={checkedCredentials.length !== 1}  // Disabled until one checkbox is selected
          >
            Load
          </button>
        </div>
      </div>

      <div className="credentials-list">
        <h3>Stored Credentials</h3>
        {loading ? (
          <div className="loading">Loading...</div>
        ) : (
          <div className="table-container">
            <table className="credentials-table">
              <thead>
                <tr>
                  <th>Select</th>
                  <th>Domain</th>
                  <th>Username</th>
                  <th>ApiToken</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {credentials.map((cred) => (
                  <tr key={cred.id}>
                    <td>
                      <input
                        type="checkbox"
                        checked={checkedCredentials.includes(cred.id)}
                        onChange={() => handleCheckboxChange(cred.id)}
                      />
                    </td>
                    <td>{cred.domain}</td>
                    <td>{cred.username}</td>
                    <td>{cred.apiToken = '***'}</td>
                    <td>
                      <button
                        className="delete-button"
                        onClick={() => handleDelete(cred.id)}
                        disabled={!checkedCredentials.includes(cred.id)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Pass the selected credentials to ImportDataSidebar */}
      {selectedCredential && <ImportDataSidebar credentials={selectedCredential} />}
    </div>
  );
}

export default Settings;
